  ('social-worker-moex-01258', 'social-worker', 'social-worker-moex-110-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '我國長期照顧服務法中，為擴增及普及長照服務量能，促進相關資源之發展，應設置特種基金。 有關特種基金來源之敘述，下列何者錯誤？', '["基金孳息收入、捐贈收入", "遺產稅及贈與稅稅率由15%調增至25%以內所增加之稅課收入，其稅課收入不適用財政收支劃 分法之規定", "菸酒稅菸品應徵稅額由每千支徵收新臺幣590元調增至新臺幣1,590元所增加之稅課收入，其 稅課收入不適用財政收支劃分法之規定", "菸品健康福利捐"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:08+00:00", "source_pdf_sha1": "6100a28843a9", "answer_pdf_sha1": "6db6a444bcb0", "source_family": "moex-gov-tw", "moex": {"exam_code": "110030", "c": "105", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "110", "exam_name": "110年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": 38, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
